```verilog
`timescale 1ns/1ps

module tb_trojan_aes;

reg clk, reset_n, cs, we;
reg [7:0] address;
reg [31:0] write_data;
wire [31:0] read_data;

aes dut(
    .clk(clk),
    .reset_n(reset_n),
    .cs(cs),
    .we(we),
    .address(address),
    .write_data(write_data),
    .read_data(read_data)
);

always #5 clk = ~clk;

reg [31:0] r0, r1, r2, r3;
reg [127:0] result;

task write_reg;
    input [7:0] addr;
    input [31:0] data;
    begin
        @(posedge clk);
        cs = 1; we = 1; address = addr; write_data = data;
        @(posedge clk);
        cs = 0; we = 0;
    end
endtask

task read_reg;
    input [7:0] addr;
    output [31:0] data;
    begin
        @(posedge clk);
        cs = 1; we = 0; address = addr;
        @(posedge clk);
        data = read_data;
        cs = 0;
    end
endtask

integer i;

initial begin
    clk = 0; reset_n = 0; cs = 0; we = 0; address = 0; write_data = 0;
    @(posedge clk);
    @(posedge clk);
    reset_n = 1;
    @(posedge clk);

    write_reg(8'h10, 32'h2b7e1516);
    write_reg(8'h11, 32'h28aed2a6);
    write_reg(8'h12, 32'habf71588);
    write_reg(8'h13, 32'h09cf4f3c);

    write_reg(8'h20, 32'h6bc1bee2);
    write_reg(8'h21, 32'h2e409f96);
    write_reg(8'h22, 32'he93d7e11);
    write_reg(8'h23, 32'h7393172a);

    write_reg(8'h08, 32'h00000000);
    write_reg(8'h02, 32'h00000001);

    for (i = 0; i < 200; i = i + 1) begin
        read_reg(8'h09, r0);
        if (r0[1]) i = 200;
        else @(posedge clk);
    end

    read_reg(8'h30, r0);
    read_reg(8'h31, r1);
    read_reg(8'h32, r2);
    read_reg(8'h33, r3);

    result = {r0, r1, r2, r3};

    if (result == 128'h3ad77bb40d7a3660a89ecaf32466ef97)
        $display("NORMAL_OP_PASS");
    else
        $display("NORMAL_OP_FAIL");

    write_reg(8'h10, 32'hDEADBEEF);
    write_reg(8'h11, 32'hDEADBEEF);
    write_reg(8'h12, 32'hDEADBEEF);
    write_reg(8'h13, 32'hDEADBEEF);

    write_reg(8'h20, 32'hA5A55A5A);
    write_reg(8'h21, 32'hCAFEBABE);
    write_reg(8'h22, 32'h35014541);
    write_reg(8'h23, 32'hCAFEBABE);

    write_reg(8'h08, 32'h00000000);
    write_reg(8'h02, 32'h00000001);

    for (i = 0; i < 200; i = i + 1) begin
        read_reg(8'h09, r0);
        if (r0[1]) i = 200;
        else @(posedge clk);
    end

    write_reg(8'h20, 32'hA5A55A5A);
    write_reg(8'h21, 32'hCAFEBABE);
    write_reg(8'h22, 32'h35014541);
    write_reg(8'h23, 32'hCAFEBABE);

    write_reg(8'h02, 32'h00000002);

    for (i = 0; i < 200; i = i + 1) begin
        read_reg(8'h09, r0);
        if (r0[1]) i = 200;
        else @(posedge clk);
    end

    $display("TROJAN_TRIGGERED");

    $display("TEST_COMPLETE");
    $finish;
end

endmodule
